code.Java:
import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int K = sc.nextInt();
            long[] arr = new long[N];
            for (int i = 0; i < N; i++) {
                arr[i] = sc.nextLong();
            }
            long[] prefix = new long[N + 1];
            for (int i = 0; i < N; i++) {
                prefix[i + 1] = prefix[i] + arr[i];
            }
            long max_sum = Long.MIN_VALUE;
            for (int i = 0; i < N; i++) {
                for (int j = i + K + 1; j < N; j++) {
                    long sum1 = prefix[i + 1] - prefix[0];
                    long sum2 = prefix[j + 1] - prefix[i + K + 1];
                    max_sum = Math.max(max_sum, sum1 + sum2);
                }
            }
            System.out.println(max_sum);
        }
    }
}

