const fs = require('fs');
const input = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;
const readline = () => input[idx++];
const T = parseInt(readline());
for (let i = 0; i < T; i++) {
    const [N, K] = readline().split(' ').map(Number);
    const arr = readline().split(' ').map(Number);
    const prefix = new Array(N + 1).fill(0);
    for (let j = 0; j < N; j++) {
        prefix[j + 1] = prefix[j] + arr[j];
    }
    let max_sum = -Infinity;
    for (let j = 0; j < N; j++) {
        for (let k = j + K + 1; k < N; k++) {
            const sum1 = prefix[j + 1] - prefix[0];
            const sum2 = prefix[k + 1] - prefix[j + K + 1];
            max_sum = Math.max(max_sum, sum1 + sum2);
        }
    }
    console.log(max_sum);
}

